import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { NotificationCategory } from '../../src/models/user-preferences.js';
import {
  ALL_NOTIFICATION_CATEGORIES,
  DEFAULT_EMAIL_PREFERENCES,
} from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let eventBus: EventBus;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    eventBus = new EventBus();
    service = new PreferencesService(preferencesRepo, eventBus);
  });

  // ---------------------------------------------------------------------------
  // createPreferences
  // ---------------------------------------------------------------------------

  describe('createPreferences', () => {
    it('should create preferences with all defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-0001' });

      expect(prefs.id).toBe('user-0001');
      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
      expect(prefs.createdAt).toBeInstanceOf(Date);
      expect(prefs.updatedAt).toBeInstanceOf(Date);
    });

    it('should create preferences with custom email enabled setting', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      expect(prefs.email.enabled).toBe(false);
      // Other fields should use defaults
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create preferences with custom frequency', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: { frequency: 'daily_digest' },
      });

      expect(prefs.email.frequency).toBe('daily_digest');
      expect(prefs.email.enabled).toBe(true);
    });

    it('should create preferences with custom subscribed categories', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: { subscribedCategories: ['order_confirmations'] },
      });

      expect(prefs.email.subscribedCategories).toEqual(['order_confirmations']);
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
    });

    it('should create preferences with all custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: true,
          frequency: 'weekly_digest',
          subscribedCategories: ['order_status_updates', 'promotions'],
        },
      });

      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('weekly_digest');
      expect(prefs.email.subscribedCategories).toEqual([
        'order_status_updates',
        'promotions',
      ]);
    });

    it('should reject duplicate preferences for same user', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(() => {
        service.createPreferences({ userId: 'user-0001' });
      }).toThrow('Preferences already exist for user: user-0001');
    });

    it('should allow preferences for different users', () => {
      const prefs1 = service.createPreferences({ userId: 'user-0001' });
      const prefs2 = service.createPreferences({ userId: 'user-0002' });

      expect(prefs1.userId).toBe('user-0001');
      expect(prefs2.userId).toBe('user-0002');
    });
  });

  // ---------------------------------------------------------------------------
  // getPreferences
  // ---------------------------------------------------------------------------

  describe('getPreferences', () => {
    it('should return preferences for existing user', () => {
      service.createPreferences({ userId: 'user-0001' });

      const prefs = service.getPreferences('user-0001');
      expect(prefs).toBeDefined();
      expect(prefs?.userId).toBe('user-0001');
    });

    it('should return undefined for user without preferences', () => {
      const prefs = service.getPreferences('user-0001');
      expect(prefs).toBeUndefined();
    });

    it('should return correct email settings after creation', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false, frequency: 'daily_digest' },
      });

      const prefs = service.getPreferences('user-0001');
      expect(prefs?.email.enabled).toBe(false);
      expect(prefs?.email.frequency).toBe('daily_digest');
    });
  });

  // ---------------------------------------------------------------------------
  // updatePreferences
  // ---------------------------------------------------------------------------

  describe('updatePreferences', () => {
    it('should update email enabled setting', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      // Other fields should be unchanged
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'weekly_digest' },
      });

      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { subscribedCategories: ['order_confirmations'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['order_confirmations']);
    });

    it('should update all email settings at once', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: {
          enabled: false,
          frequency: 'daily_digest',
          subscribedCategories: [],
        },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('daily_digest');
      expect(updated.email.subscribedCategories).toEqual([]);
    });

    it('should update the updatedAt timestamp', () => {
      const original = service.createPreferences({ userId: 'user-0001' });
      const originalUpdatedAt = original.updatedAt;

      // Small delay to ensure timestamp difference
      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(
        originalUpdatedAt.getTime(),
      );
    });

    it('should throw for non-existent user preferences', () => {
      expect(() => {
        service.updatePreferences('user-9999', { email: { enabled: false } });
      }).toThrow('Preferences not found for user: user-9999');
    });

    it('should preserve unchanged fields on partial update', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: true,
          frequency: 'daily_digest',
          subscribedCategories: ['order_confirmations', 'promotions'],
        },
      });

      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'weekly_digest' },
      });

      expect(updated.email.enabled).toBe(true);
      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmations',
        'promotions',
      ]);
    });
  });

  // ---------------------------------------------------------------------------
  // deletePreferences
  // ---------------------------------------------------------------------------

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-0001' });

      const result = service.deletePreferences('user-0001');
      expect(result).toBe(true);
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });

    it('should return false for non-existent preferences', () => {
      const result = service.deletePreferences('user-9999');
      expect(result).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // getOrCreatePreferences
  // ---------------------------------------------------------------------------

  describe('getOrCreatePreferences', () => {
    it('should create preferences with defaults if none exist', () => {
      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return existing preferences if already created', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      const prefs = service.getOrCreatePreferences('user-0001');
      expect(prefs.email.enabled).toBe(false);
    });

    it('should not create duplicate preferences on repeated calls', () => {
      service.getOrCreatePreferences('user-0001');
      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.userId).toBe('user-0001');
      // Should not throw
    });
  });

  // ---------------------------------------------------------------------------
  // isNotificationEnabled
  // ---------------------------------------------------------------------------

  describe('isNotificationEnabled', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.isNotificationEnabled('user-0001', 'order_confirmations')).toBe(
        true,
      );
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations', 'order_status_updates'],
        },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_confirmations')).toBe(
        true,
      );
      expect(service.isNotificationEnabled('user-0001', 'order_status_updates')).toBe(
        true,
      );
    });

    it('should return false when email is disabled (master toggle)', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_confirmations')).toBe(
        false,
      );
      expect(service.isNotificationEnabled('user-0001', 'order_status_updates')).toBe(
        false,
      );
    });

    it('should return false when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_confirmations')).toBe(
        true,
      );
      expect(service.isNotificationEnabled('user-0001', 'order_status_updates')).toBe(
        false,
      );
      expect(service.isNotificationEnabled('user-0001', 'promotions')).toBe(false);
    });

    it('should return false when email is disabled even if category is subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: false,
          subscribedCategories: ALL_NOTIFICATION_CATEGORIES,
        },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_confirmations')).toBe(
        false,
      );
    });

    it('should return false when subscribed categories is empty', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: true,
          subscribedCategories: [],
        },
      });

      expect(service.isNotificationEnabled('user-0001', 'order_confirmations')).toBe(
        false,
      );
      expect(service.isNotificationEnabled('user-0001', 'order_status_updates')).toBe(
        false,
      );
    });
  });

  // ---------------------------------------------------------------------------
  // isEmailEnabled
  // ---------------------------------------------------------------------------

  describe('isEmailEnabled', () => {
    it('should return true when no preferences exist', () => {
      expect(service.isEmailEnabled('user-0001')).toBe(true);
    });

    it('should return true when email is enabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true },
      });

      expect(service.isEmailEnabled('user-0001')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      expect(service.isEmailEnabled('user-0001')).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // DEFAULT_EMAIL_PREFERENCES constant
  // ---------------------------------------------------------------------------

  describe('DEFAULT_EMAIL_PREFERENCES', () => {
    it('should have email enabled by default', () => {
      expect(DEFAULT_EMAIL_PREFERENCES.enabled).toBe(true);
    });

    it('should have immediate frequency by default', () => {
      expect(DEFAULT_EMAIL_PREFERENCES.frequency).toBe('immediate');
    });

    it('should subscribe to all categories by default', () => {
      expect(DEFAULT_EMAIL_PREFERENCES.subscribedCategories).toEqual(
        ALL_NOTIFICATION_CATEGORIES,
      );
    });
  });
});

// =============================================================================
// Integration: NotificationService with PreferencesService
// =============================================================================

describe('NotificationService with PreferencesService', () => {
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let eventBus: EventBus;
  let preferencesService: PreferencesService;
  let notificationService: NotificationService;

  beforeEach(() => {
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    eventBus = new EventBus();
    preferencesService = new PreferencesService(preferencesRepo, eventBus);
    notificationService = new NotificationService(eventBus, preferencesService);
    resetNotificationIdCounter();
  });

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const orderStatusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  // ---------------------------------------------------------------------------
  // Backward compatibility (no preferences configured)
  // ---------------------------------------------------------------------------

  describe('backward compatibility', () => {
    it('should send all notifications when no preferences exist for user', async () => {
      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Confirmation',
      );
    });

    it('should send status update notifications when no preferences exist', async () => {
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Update',
      );
    });
  });

  // ---------------------------------------------------------------------------
  // No preferences service (backward compatibility)
  // ---------------------------------------------------------------------------

  describe('without preferences service', () => {
    it('should send all notifications when no preferences service is attached', async () => {
      const serviceWithoutPrefs = new NotificationService(eventBus);

      // The handler was already registered by `notificationService` above,
      // so we need a fresh event bus
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);

      await freshEventBus.emit({
        ...orderCreatedEvent,
      });

      expect(freshNotifService.getNotificationCount()).toBe(1);
    });
  });

  // ---------------------------------------------------------------------------
  // Email disabled (master toggle)
  // ---------------------------------------------------------------------------

  describe('email disabled (master toggle)', () => {
    it('should suppress order confirmation when email is disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should suppress order status update when email is disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should suppress all notifications when email is disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Category-based filtering
  // ---------------------------------------------------------------------------

  describe('category-based filtering', () => {
    it('should send order confirmation when category is subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress order confirmation when category is not subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      await eventBus.emit(orderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should send status update when category is subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress status update when category is not subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should allow selective categories — confirmations only', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_confirmations'],
        },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Confirmation',
      );
    });

    it('should allow selective categories — status updates only', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.subject).toContain(
        'Order Update',
      );
    });

    it('should suppress all notifications when subscribed categories is empty', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: [],
        },
      });

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(orderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Dynamic preference changes
  // ---------------------------------------------------------------------------

  describe('dynamic preference changes', () => {
    it('should respect updated preferences for subsequent notifications', async () => {
      // Start with all notifications enabled
      preferencesService.createPreferences({ userId: 'user-1' });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);

      // Disable email
      preferencesService.updatePreferences('user-1', {
        email: { enabled: false },
      });

      await eventBus.emit(orderStatusChangedEvent);
      // Should still be 1 — the second notification was suppressed
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should resume sending after re-enabling email', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(0);

      // Re-enable email
      preferencesService.updatePreferences('user-1', {
        email: { enabled: true },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should resume after deleting preferences (reverts to defaults)', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(0);

      // Delete preferences → revert to default (all enabled)
      preferencesService.deletePreferences('user-1');

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
    });
  });

  // ---------------------------------------------------------------------------
  // setPreferencesService
  // ---------------------------------------------------------------------------

  describe('setPreferencesService', () => {
    it('should allow attaching a preferences service after construction', async () => {
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);

      // Without preferences service, notifications should be sent
      await freshEventBus.emit(orderCreatedEvent);
      expect(freshNotifService.getNotificationCount()).toBe(1);

      // Attach preferences service with email disabled
      const freshPrefsService = new PreferencesService(preferencesRepo, freshEventBus);
      freshPrefsService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });
      freshNotifService.setPreferencesService(freshPrefsService);

      await freshEventBus.emit(orderCreatedEvent);
      // Should still be 1 — the second notification was suppressed
      expect(freshNotifService.getNotificationCount()).toBe(1);
    });

    it('should allow removing the preferences service', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(0);

      // Remove preferences service → all notifications sent again
      notificationService.setPreferencesService(undefined);

      await eventBus.emit(orderCreatedEvent);
      expect(notificationService.getNotificationCount()).toBe(1);
    });
  });

  // ---------------------------------------------------------------------------
  // Multi-user scenarios
  // ---------------------------------------------------------------------------

  describe('multi-user scenarios', () => {
    it('should enforce per-user preferences independently', async () => {
      // User 1: disable order confirmations
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['order_status_updates'],
        },
      });

      // User 2: enable everything
      preferencesService.createPreferences({
        userId: 'user-2',
        email: {
          enabled: true,
          subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
        },
      });

      // Emit order created for user 1 (should be suppressed)
      await eventBus.emit(orderCreatedEvent);

      // Emit order created for user 2 (should be sent)
      await eventBus.emit({
        ...orderCreatedEvent,
        user: {
          ...orderCreatedEvent.user,
          id: 'user-2',
          email: 'bob@example.com',
        },
        order: { ...orderCreatedEvent.order, userId: 'user-2' },
      });

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.recipient).toBe(
        'bob@example.com',
      );
    });
  });

  // ---------------------------------------------------------------------------
  // send() public API (should NOT check preferences)
  // ---------------------------------------------------------------------------

  describe('send() public API', () => {
    it('should always send via public API regardless of preferences', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const notification = await notificationService.send({
        recipient: 'alice@example.com',
        subject: 'Direct notification',
        body: 'This should go through regardless of preferences',
        channel: 'email',
      });

      // Public send() does not check preferences
      expect(notification.status).toBe('failed'); // No adapter registered, but it was attempted
      expect(notificationService.getNotificationCount()).toBe(1);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';

describe('PreferencesRepository', () => {
  let db: Database;
  let repo: PreferencesRepository;

  const createPreferences = (userId: string): UserPreferences => ({
    id: userId,
    userId,
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
    },
    createdAt: new Date(),
    updatedAt: new Date(),
  });

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
  });

  it('should save and retrieve preferences', () => {
    const prefs = createPreferences('user-0001');
    repo.save(prefs);

    const found = repo.findById('user-0001');
    expect(found).toBeDefined();
    expect(found?.userId).toBe('user-0001');
    expect(found?.email.enabled).toBe(true);
    expect(found?.email.frequency).toBe('immediate');
  });

  it('should find preferences by user ID', () => {
    const prefs = createPreferences('user-0001');
    repo.save(prefs);

    const found = repo.findByUserId('user-0001');
    expect(found).toBeDefined();
    expect(found?.userId).toBe('user-0001');
  });

  it('should return undefined for non-existent user', () => {
    const found = repo.findByUserId('user-9999');
    expect(found).toBeUndefined();
  });

  it('should correctly serialize and deserialize subscribed categories', () => {
    const prefs = createPreferences('user-0001');
    prefs.email.subscribedCategories = ['order_confirmations', 'promotions'];
    repo.save(prefs);

    const found = repo.findById('user-0001');
    expect(found?.email.subscribedCategories).toEqual([
      'order_confirmations',
      'promotions',
    ]);
  });

  it('should handle empty subscribed categories', () => {
    const prefs = createPreferences('user-0001');
    prefs.email.subscribedCategories = [];
    repo.save(prefs);

    const found = repo.findById('user-0001');
    expect(found?.email.subscribedCategories).toEqual([]);
  });

  it('should update preferences', () => {
    const prefs = createPreferences('user-0001');
    repo.save(prefs);

    repo.update('user-0001', {
      email: {
        enabled: false,
        frequency: 'daily_digest',
        subscribedCategories: ['order_confirmations'],
      },
    });

    const found = repo.findById('user-0001');
    expect(found?.email.enabled).toBe(false);
    expect(found?.email.frequency).toBe('daily_digest');
    expect(found?.email.subscribedCategories).toEqual(['order_confirmations']);
  });

  it('should delete preferences', () => {
    const prefs = createPreferences('user-0001');
    repo.save(prefs);

    expect(repo.delete('user-0001')).toBe(true);
    expect(repo.findById('user-0001')).toBeUndefined();
  });

  it('should correctly round-trip date serialization', () => {
    const prefs = createPreferences('user-0001');
    const originalCreatedAt = prefs.createdAt;
    repo.save(prefs);

    const found = repo.findById('user-0001');
    expect(found?.createdAt).toBeInstanceOf(Date);
    expect(found?.createdAt.getTime()).toBe(originalCreatedAt.getTime());
  });

  it('should count preferences records', () => {
    expect(repo.count()).toBe(0);

    repo.save(createPreferences('user-0001'));
    expect(repo.count()).toBe(1);

    repo.save(createPreferences('user-0002'));
    expect(repo.count()).toBe(2);
  });
});

